final:
module T_latch (  
    input wire T,  
    input wire clk,  
    input wire reset,  
    output reg Q  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset)  
            Q <= 0;  
        else if (T)  
            Q <= ~Q;  
    end  
  always @(*) begin
    if (1'b0) begin
      if (Q) begin
        Q <= 0;
      end
    end
  end

endmodule
